VALUES
  ('social-worker-moex-00791', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作者對「種族歧視」運用與了解，下列敘述何者錯誤？', '["基於尊重的原則，社會工作者應支持服務對象對他族的種族歧視", "制度性歧視經常造成或導致文化和環境種族主義", "文化和種族主義的案例對社會工作者處遇措施的挑戰，比個人行為更大", "對種族定性的偏誤，將提高特定種族落入被逮捕或定罪的處境"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00792', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當社會工作者將種族和族群作為對健康風險預測的因子時，下列敘述何者錯誤？', '["應意識到「種族和族群」可能只是這群人健康弱勢的替代性指標", "為提升種族和族群的健康，應將此變項作為預測健康結果的獨立因素", "須避免混淆「種族作為風險因子」和「種族作為疾病的生物印記」", "致力釐清不同（或少數）種族或族群在實際服務經驗是否有所差異"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00793', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關社會排除的敘述，下列何者錯誤？', '["社會排除概念主要是指經濟匱乏", "社會排除概念涉及的面向並非單指經濟匱乏，而是以排除的多面向所造成個人經濟面與非經濟 面匱乏及剝奪的動態累積過程來闡述", "社會排除的論述根植於古典社會學理論，如韋伯（MaxWeber）主張某些群體可以藉由「社會封 閉」（socialclosure）的過程，犧牲其他群體的利益，以確保及維持自身的特權", "社會排除常涉及自由權、政治權以及社會權的剝奪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00794', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '經濟弱勢與少數族群兒童在一般公立學校體系常面臨的障礙，下列敘述何者錯誤？', '["父母對兒童在學校表現的期許可能不高", "教師對於弱勢家庭孩子可能有較低期許", "教材缺乏文化的相關性、無法引起學生共鳴", "弱勢學生不管表現多差，學校都讓他們升級，這種自動升級的方式能夠有效鼓勵學生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00795', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '許多貧困家庭大部分精力都花在滿足食物和住所方面，沒有動力多想歸屬感和成就感的需求。這 是下列何種理論的觀點？', '["貧窮文化", "社會需求理論", "成就需求理論", "Maslow需求階層論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00796', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年暴力與犯罪的成因是多面向的交互作用，貧窮也可能是巨視層面的因素之一，下列敘述何 者錯誤？', '["貧窮家庭父母較難取得充分的孩童教養資源", "父母經濟和生活壓力極大，經常打罵孩子", "社區中可能缺乏適當教育設施，造成學生的學業成就低落", "許多貧窮的都會社區犯罪率高，兒童接觸暴力風險也較高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00797', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在 Erikson 的發展理論中，若父母或是家庭主要照顧者無法持續提供孩子足夠的照顧和溫暖，試 問在那一發展階段會引起不信任危機？', '["嬰兒期", "幼兒期", "遊戲期", "學齡期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00798', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '如果父母習慣使用控制的手段，讓孩子在生活和情感上都過度依賴父母，無法讓孩子發展獨立自 主與自我認同，這是在Erikson的發展理論中，那一階段的發展危機？', '["兒童早期", "兒童中期", "青少年期", "成年初期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "d53a9f1e9d22", "answer_pdf_sha1": "5445b07c01bb", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00799', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '社會工作者在進行家庭評估時，必須特別注意家庭的功能影響，家庭功
能評估的面向為何？請舉例說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00800', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '許多社會工作的倫理兩難多半與直接實務工作有關，然而，在社區組織、
社會政策與計畫等的間接實務工作也會發生倫理兩難的議題，其中最常
發生的就是分配有限資源的議題。請依 Reamer 所提出的分配有限資源
的四種標準，運用於以下案例。
案例：您是提供物質濫用者相關服務基金會的主管，長期以來提供物質
濫用者諮商與支持性服務，多年來基金會的經費是透過承接政府方案而
來。政府今年度雖仍提供相關方案，但是經費卻較去年減少百分之三十，
這將影響原本服務的規模。請問您如何應用上述的四種資源分配的標準
提供案主服務？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "fcc05a79b803", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
